                ds_retrieveResult.NameValue(ds_retrieveResult.RowPosition, "selpchItemNm") = rtnList[1];

                //var row = ds_retrieveResult.NameValueRow("selpchItemCd",rtnList[0]);

                //if ( row != "" ) {
